    'GemiMark.app': { price: 30, tag: 'edu', desc: 'Live Markdown HTML Editor.', icon: '📝', title: 'GemiMark IDE', width: 700, html: (pid) => `<div style="display:flex; flex-grow:1; gap:10px;"><textarea id="md-in-${pid}" oninput="GemiOS.Registry['GemiMark.app'].parse(${pid})" style="flex:1; background:#1e1e1e; color:#d4d4d4; font-family:monospace; padding:15px; border:none; border-radius:6px; resize:none; outline:none; font-size:14px;" spellcheck="false"># GemiMark\n\nLive **Markdown** rendering.\n\n* Fast\n* Native\n* Cool</textarea><div id="md-out-${pid}" style="flex:1; background:rgba(255,255,255,0.9); color:black; padding:15px; border-radius:6px; overflow-y:auto; font-family:sans-serif;"><h1>GemiMark</h1><p>Live <b>Markdown</b> rendering.</p><ul><li>Fast</li><li>Native</li><li>Cool</li></ul></div></div>`, parse: (pid) => { let txt = document.getElementById(`md-in-${pid}`).value; let html = txt.replace(/^### (.*$)/gim, '<h3>$1</h3>').replace(/^## (.*$)/gim, '<h2>$1</h2>').replace(/^# (.*$)/gim, '<h1>$1</h1>').replace(/^\> (.*$)/gim, '<blockquote>$1</blockquote>').replace(/\*\*(.*)\*\*/gim, '<b>$1</b>').replace(/\*(.*)\*/gim, '<i>$1</i>').replace(/^\* (.*$)/gim, '<ul><li>$1</li></ul>').replace(/<\/ul>\n<ul>/gim, '').replace(/\n$/gim, '<br>'); document.getElementById(`md-out-${pid}`).innerHTML = html; } },
    'Calculator.app': { price: 10, tag: 'edu', id: 'app_calc', icon: '🧮', desc: 'Standard arithmetic calculator.', title: 'Calculator', width: 260, html: (pid) => `<div style="background:rgba(255,255,255,0.9); color:black; padding:15px; font-size:28px; text-align:right; margin-bottom:10px; border-radius:6px; font-family:monospace;" id="cd-${pid}">0</div><div style="display:grid; grid-template-columns:repeat(4,1fr); gap:6px; flex-grow:1;">${['7','8','9','/','4','5','6','*','1','2','3','-','C','0','=','+'].map(b=>`<button style="padding:15px; background:rgba(255,255,255,0.2); border:1px solid rgba(255,255,255,0.1); cursor:pointer; font-weight:bold; border-radius:6px; color:inherit; font-size:16px;" onclick="let d=document.getElementById('cd-${pid}'); if('${b}'==='C') d.innerText='0'; else if('${b}'==='=') { try { d.innerText=eval(d.innerText); } catch(e){ d.innerText='Err'; } } else { if(d.innerText==='0') d.innerText='${b}'; else d.innerText+='${b}'; }">${b}</button>`).join('')}</div>` },
